class Shape {
  area() {
    throw new Error(`${this.constructor.name} must implement area()`);
  }
  describe() {
    return `${this.constructor.name} with area ${this.area().toFixed(2)}`;
  }
}

class Circle extends Shape {
  constructor(radius) { super(); this.radius = radius; }
  area() { return Math.PI * this.radius ** 2; }
}

class Rectangle extends Shape {
  constructor(w, h) { super(); this.width = w; this.height = h; }
  area() { return this.width * this.height; }
}

console.log(new Circle(5).describe());
console.log(new Rectangle(4, 6).describe());

const canWalk = {
  walk() { return `${this.name} is walking.`; }
};
const canTalk = {
  talk(msg) { return `${this.name} says: ${msg}`; }
};
const canCalculate = {
  calculate(a, b) { return `${this.name} calculated: ${a + b}`; }
};

// Compose Robot by mixing all three abilities:
const Robot = Object.assign({ name: "R2D2" }, canWalk, canTalk, canCalculate);

console.log(Robot.walk());
console.log(Robot.talk("Hello, humans."));
console.log(Robot.calculate(5, 7));
